const ROLE_PREFIXES = ['info','admin','sales','support','abuse','postmaster','noreply','no-reply','contact','hello','office'];
const out = [];
for (const item of $input.all()) {
  const raw = item.json;
  const email = String(raw.email || '').trim().toLowerCase();
  const localPart = email.split('@')[0] || '';
  const domain = email.split('@')[1] || '';
  const emailValid = /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
  const isRoleBased = ROLE_PREFIXES.indexOf(localPart) !== -1;
  const phoneDigits = String(raw.phone || '').replace(/[^0-9]/g, '');
  const phoneE164ish = phoneDigits ? ('+' + phoneDigits) : '';
  const reasons = [];
  if (!emailValid) reasons.push('invalid_email_syntax');
  if (isRoleBased) reasons.push('role_based_address');
  out.push({ json: Object.assign({}, raw, {
    email: email, domain: domain, phone: phoneE164ish,
    emailValid: emailValid, isRoleBased: isRoleBased,
    accepted: emailValid && !isRoleBased, rejectReasons: reasons
  }) });
}
return out;

const FREE = ['gmail.com','yahoo.com','outlook.com','hotmail.com','icloud.com','aol.com','proton.me'];
const out = [];
for (const item of $input.all()) {
  const j = item.json;
  const domain = j.domain || '';
  const isFreeMail = FREE.indexOf(domain) !== -1;
  const root = domain.split('.').slice(-2, -1)[0] || domain;
  const companyGuess = isFreeMail ? null : (root ? root.charAt(0).toUpperCase() + root.slice(1) : null);
  out.push({ json: Object.assign({}, j, { isFreeMail: isFreeMail, companyGuess: companyGuess }) });
}
return out;

// Synthetic 'already in CRM' set. In production this is a CRM lookup node.
const EXISTING = ['liam@initech.dev'];
const seenThisRun = [];
const out = [];
for (const item of $input.all()) {
  const j = item.json;
  const email = j.email;
  const dupInBatch = seenThisRun.indexOf(email) !== -1;
  seenThisRun.push(email);
  const existsInCrm = EXISTING.indexOf(email) !== -1;
  const status = (dupInBatch || existsInCrm) ? 'returning' : 'new';
  out.push({ json: Object.assign({}, j, { dupInBatch: dupInBatch, existsInCrm: existsInCrm, contactStatus: status }) });
}
return out;

const OWNERS = ['alex@oldev.site', 'sam@oldev.site', 'jordan@oldev.site'];
const out = [];
let i = 0;
for (const item of $input.all()) {
  const owner = OWNERS[i % OWNERS.length];
  i++;
  out.push({ json: Object.assign({}, item.json, { assignedOwner: owner }) });
}
return out;
